# ======================================
# Data loading
# ======================================
@st.cache_data(show_spinner=False)
def load_data(path: str) -> pd.DataFrame:
    df = pd.read_csv(path)

    numeric_cols = [
        "apartmentsize",
        "age",
        "remainingstay_days",
        DISPLAY_IMPORTANCE_COL,
        *LIFESTYLE_FEATURES,
        "extraversion",
        "agreeableness",
        "conscientiousness",
        "emotional_stability",
        "openness",
    ]
    for col in numeric_cols:
        if col in df.columns:
            df[col] = pd.to_numeric(df[col], errors="coerce")

    return df


def extract_unit_number(unit_value: str) -> int | None:
    if pd.isna(unit_value):
        return None
    try:
        return int(str(unit_value).split(".")[-1])
    except (ValueError, TypeError):
        return None


@st.cache_data(show_spinner=False)
def build_vacant_units(df_in: pd.DataFrame) -> pd.DataFrame:
    vacant_units = []

    for apt, group in df_in.groupby("apartment"):
        size_raw = group["apartmentsize"].iloc[0]
        if pd.isna(size_raw):
            continue

        size = int(size_raw)
        existing_units = group["unit"].dropna().astype(str).tolist()
        existing_numbers = [
            n for n in (extract_unit_number(u) for u in existing_units)
            if n is not None
        ]

        full_range = set(range(1, size + 1))
        missing_numbers = sorted(full_range - set(existing_numbers))

        for num in missing_numbers:
            vacant_units.append({
                "apartment": apt,
                "vacant_unit": f"{apt}.{num}",
            })

    return pd.DataFrame(vacant_units)


@st.cache_data(show_spinner=False)
def build_personality_matrices_cached(df_in: pd.DataFrame) -> dict[str, pd.DataFrame]:
    return build_personality_matrices(
        df_in=df_in,
        profiles=PERSONALITY_PROFILES,
        id_col="unit",
    )


# ======================================
# Lifestyle layer
# ======================================
def build_feature_ranges(df_in: pd.DataFrame, feature_cols: list[str]) -> dict:
    ranges = {}
    for col in feature_cols:
        col_min = float(df_in[col].min())
        col_max = float(df_in[col].max())

        if pd.isna(col_min) or pd.isna(col_max) or col_max <= col_min:
            raise ValueError(
                f"Feature '{col}' has no usable range: min={col_min}, max={col_max}"
            )

        ranges[col] = {
            "min": col_min,
            "max": col_max,
            "span": col_max - col_min,
        }
    return ranges


def lifestyle_similarity_component(a: float, b: float, span: float) -> float:
    if pd.isna(a) or pd.isna(b):
        return np.nan
    return float(np.clip(1.0 - (abs(a - b) / span), 0.0, 1.0))


def lifestyle_compatibility_between_rows(
    row_i: pd.Series,
    row_j: pd.Series,
    *,
    feature_cols: list[str],
    feature_ranges: dict,
    weights: dict | None = None,
) -> float:
    if weights is None:
        weights = {f: 1.0 for f in feature_cols}

    num = 0.0
    den = 0.0

    for f in feature_cols:
        w = float(weights.get(f, 1.0))
        span = float(feature_ranges[f]["span"])
        s = lifestyle_similarity_component(row_i[f], row_j[f], span=span)

        if pd.notna(s):
            num += w * s
            den += w

    return num / den if den else np.nan


def lifestyle_compatibility_matrix(
    df_in: pd.DataFrame,
    *,
    feature_cols: list[str],
    feature_ranges: dict,
    weights: dict | None = None,
    id_col: str = "unit",
) -> pd.DataFrame:
    work_df = df_in.copy()

    if id_col in work_df.columns:
        if work_df[id_col].duplicated().any():
            raise ValueError(f"Column '{id_col}' contains duplicate IDs.")
        work_df = work_df.set_index(id_col, drop=False)

    n = len(work_df)
    M = np.eye(n, dtype=float)

    for i in range(n):
        for j in range(i + 1, n):
            s = lifestyle_compatibility_between_rows(
                work_df.iloc[i],
                work_df.iloc[j],
                feature_cols=feature_cols,
                feature_ranges=feature_ranges,
                weights=weights,
            )

            if pd.isna(s):
                s = 0.0

            M[i, j] = s
            M[j, i] = s

    return pd.DataFrame(M, index=work_df.index, columns=work_df.index)


@st.cache_data(show_spinner=False)
def build_lifestyle_matrix_cached(df_in: pd.DataFrame) -> pd.DataFrame:
    feature_ranges = build_feature_ranges(df_in, LIFESTYLE_FEATURES)
    lifestyle_weights = {f: 1.0 for f in LIFESTYLE_FEATURES}

    return lifestyle_compatibility_matrix(
        df_in=df_in,
        feature_cols=LIFESTYLE_FEATURES,
        feature_ranges=feature_ranges,
        weights=lifestyle_weights,
        id_col="unit",
    )


# ======================================
# Personalization
# ======================================
def get_layer_weights(
    importance_value: float,
    observed_min: float,
    observed_max: float,
    min_personality_weight: float = 0.40,
    max_personality_weight: float = 0.70,
) -> dict:
    if observed_max <= observed_min or pd.isna(importance_value):
        p_weight = 0.55
    else:
        x = (float(importance_value) - observed_min) / (observed_max - observed_min)
        x = float(np.clip(x, 0.0, 1.0))
        p_weight = min_personality_weight + x * (max_personality_weight - min_personality_weight)

    l_weight = 1.0 - p_weight

    return {
        "personality_weight": p_weight,
        "lifestyle_weight": l_weight,
    }


def build_final_pairwise_matrix(
    C_personality: pd.DataFrame,
    C_lifestyle: pd.DataFrame,
    personality_weight: float,
    lifestyle_weight: float,
) -> pd.DataFrame:
    return personality_weight * C_personality + lifestyle_weight * C_lifestyle


# ======================================
# Structural metrics
# ======================================
def coalition_member_utilities(submatrix: pd.DataFrame) -> pd.Series:
    utilities = {}
    for member in submatrix.index:
        others = submatrix.columns[submatrix.columns != member]
        utilities[member] = submatrix.loc[member, others].mean()
    return pd.Series(utilities)


def coalition_metrics(submatrix: pd.DataFrame) -> dict:
    utilities = coalition_member_utilities(submatrix)
    pair_values = upper_triangle_values(submatrix)

    return {
        "harmony": float(utilities.mean()),
        "fairness": float(utilities.min()),
        "min_pair": float(pair_values.min()),
        "mean_pair": float(pair_values.mean()),
        "max_pair": float(pair_values.max()),
        "utility_std": float(utilities.std()),
    }


def applicant_vacancy_structural_scores(
    applicant_unit: str,
    vacancy_df: pd.DataFrame,
    tenant_df: pd.DataFrame,
    C_final: pd.DataFrame,
    apartment_col: str = "apartment",
    tenant_unit_col: str = "unit",
    vacancy_unit_col: str = "vacant_unit",
) -> pd.DataFrame:
    rows = []

    for _, vacant_row in vacancy_df.iterrows():
        vacant_unit = vacant_row[vacancy_unit_col]
        apt = vacant_row[apartment_col]

        residents = tenant_df.loc[
            tenant_df[apartment_col] == apt, tenant_unit_col
        ].tolist()
        residents = [u for u in residents if u != applicant_unit]

        if len(residents) == 0:
            continue

        coalition_units = residents + [applicant_unit]
        submatrix = C_final.loc[coalition_units, coalition_units]
        metrics = coalition_metrics(submatrix)

        apartment_size = tenant_df.loc[tenant_df[apartment_col] == apt, "apartmentsize"].iloc[0]

        rows.append({
            "vacant_unit": vacant_unit,
            "apartment": apt,
            "apartmentsize": apartment_size,
            "n_residents": len(residents),
            "harmony": metrics["harmony"],
            "fairness": metrics["fairness"],
            "min_pair": metrics["min_pair"],
            "mean_pair": metrics["mean_pair"],
            "max_pair": metrics["max_pair"],
            "utility_std": metrics["utility_std"],
        })

    if not rows:
        return pd.DataFrame(
            columns=[
                "vacant_unit",
                "apartment",
                "apartmentsize",
                "n_residents",
                "harmony",
                "fairness",
                "min_pair",
                "mean_pair",
                "max_pair",
                "utility_std",
            ]
        )

    return pd.DataFrame(rows).sort_values(
        by=["fairness", "harmony", "min_pair"],
        ascending=False,
    ).reset_index(drop=True)


def add_structural_score(
    df_in: pd.DataFrame,
    w_fairness: float = 0.45,
    w_harmony: float = 0.35,
    w_min_pair: float = 0.20,
) -> pd.DataFrame:
    out = df_in.copy()
    out["struct_score"] = (
        w_fairness * out["fairness"]
        + w_harmony * out["harmony"]
        + w_min_pair * out["min_pair"]
    )
    return out.sort_values(
        by=["struct_score", "fairness", "harmony"],
        ascending=False,
    ).reset_index(drop=True)


# ======================================
# Context flags
# ======================================
def normalize_flag_value(x):
    if pd.isna(x):
        return None
    x = str(x).strip().lower()
    return x if x else None


def homogeneous_group_info(values, min_residents: int = 2) -> tuple[bool, str | None]:
    vals = [normalize_flag_value(v) for v in values]
    vals = [v for v in vals if v is not None]

    if len(vals) < min_residents:
        return False, None

    uniq = set(vals)
    if len(uniq) == 1:
        return True, next(iter(uniq))

    return False, None


def normalize_exact_match_value(value):
    if pd.isna(value):
        return None

    if isinstance(value, str):
        value = value.strip().lower()
        return value if value else None

    try:
        value = float(value)
        return int(value) if value.is_integer() else round(value, 6)
    except (ValueError, TypeError):
        value = str(value).strip().lower()
        return value if value else None


def get_exact_shared_agreements(
    applicant_row: pd.Series,
    residents_df: pd.DataFrame,
    feature_label_map: dict[str, str],
    max_items: int = 3,
) -> list[str]:
    agreements = []

    for col, message in feature_label_map.items():
        if col not in residents_df.columns or col not in applicant_row.index:
            continue

        values = [normalize_exact_match_value(applicant_row[col])]
        values.extend(normalize_exact_match_value(v) for v in residents_df[col].tolist())

        if any(v is None for v in values):
            continue

        if len(set(values)) == 1:
            agreements.append(message)

    return agreements[:max_items]


def nearest_age_gap_info(
    applicant_age: float,
    resident_ages: pd.Series,
    threshold_years: float,
) -> tuple[bool, float, str | None]:
    if pd.isna(applicant_age):
        return False, np.nan, None

    valid_ages = pd.to_numeric(resident_ages, errors="coerce").dropna()
    if valid_ages.empty:
        return False, np.nan, None

    signed_diffs = valid_ages - float(applicant_age)
    abs_diffs = signed_diffs.abs()
    nearest_idx = abs_diffs.idxmin()

    nearest_signed_diff = float(signed_diffs.loc[nearest_idx])
    nearest_abs_diff = float(abs_diffs.loc[nearest_idx])

    if nearest_abs_diff <= threshold_years:
        return False, nearest_abs_diff, None

    direction = "older" if nearest_signed_diff > 0 else "younger"
    return True, nearest_abs_diff, direction


def applicant_vacancy_context_flags(
    applicant_unit: str,
    vacancy_df: pd.DataFrame,
    tenant_df: pd.DataFrame,
    apartment_col: str = "apartment",
    tenant_unit_col: str = "unit",
    vacancy_unit_col: str = "vacant_unit",
    age_col: str = "age",
    gender_col: str = "gender",
    nationality_col: str = "nationality",
    occupation_col: str = "occupation",
    remainingstay_col: str = "remainingstay_days",
    age_gap_threshold: float = 5.0,
    turnover_threshold_days: float = 40.0,
    high_turnover_share_cutoff: float = 0.50,
) -> pd.DataFrame:
    rows = []

    applicant_row = tenant_df.loc[tenant_df[tenant_unit_col] == applicant_unit].iloc[0]
    applicant_age = applicant_row[age_col]
    applicant_gender = normalize_flag_value(applicant_row[gender_col])
    applicant_nationality = normalize_flag_value(applicant_row[nationality_col])
    applicant_occupation = normalize_flag_value(applicant_row[occupation_col])

    for _, vacant_row in vacancy_df.iterrows():
        vacant_unit = vacant_row[vacancy_unit_col]
        apt = vacant_row[apartment_col]

        residents_df = tenant_df.loc[tenant_df[apartment_col] == apt].copy()
        residents_df = residents_df.loc[residents_df[tenant_unit_col] != applicant_unit]
        n_residents = len(residents_df)

        if n_residents == 0:
            continue

        flag_gender_homogeneous, gender_group = homogeneous_group_info(
            residents_df[gender_col].tolist(),
            min_residents=2,
        )
        flag_nationality_homogeneous, nationality_group = homogeneous_group_info(
            residents_df[nationality_col].tolist(),
            min_residents=2,
        )
        flag_occupation_homogeneous, occupation_group = homogeneous_group_info(
            residents_df[occupation_col].tolist(),
            min_residents=2,
        )

        (
            flag_age_gap,
            nearest_age_gap_years,
            nearest_age_gap_direction,
        ) = nearest_age_gap_info(
            applicant_age=applicant_age,
            resident_ages=residents_df[age_col],
            threshold_years=age_gap_threshold,
        )

        valid_remaining = residents_df[remainingstay_col].dropna()
        if len(valid_remaining) > 0:
            turnover_share_lt_threshold = float((valid_remaining < turnover_threshold_days).mean())
            flag_high_turnover = bool(turnover_share_lt_threshold >= high_turnover_share_cutoff)
        else:
            turnover_share_lt_threshold = np.nan
            flag_high_turnover = False

        shared_agreements = get_exact_shared_agreements(
            applicant_row=applicant_row,
            residents_df=residents_df,
            feature_label_map=EXACT_MATCH_LABELS,
            max_items=3,
        )
        shared_agreements_text = " | ".join(shared_agreements)

        flag_gender_diff_from_applicant = bool(
            flag_gender_homogeneous
            and gender_group is not None
            and applicant_gender is not None
            and gender_group != applicant_gender
        )
        flag_nationality_diff_from_applicant = bool(
            flag_nationality_homogeneous
            and nationality_group is not None
            and applicant_nationality is not None
            and nationality_group != applicant_nationality
        )
        flag_occupation_diff_from_applicant = bool(
            flag_occupation_homogeneous
            and occupation_group is not None
            and applicant_occupation is not None
            and occupation_group != applicant_occupation
        )

        rows.append({
            "vacant_unit": vacant_unit,
            "apartment": apt,
            "flag_age_gap": flag_age_gap,
            "nearest_age_gap_years": nearest_age_gap_years,
            "nearest_age_gap_direction": nearest_age_gap_direction,
            "flag_high_turnover": flag_high_turnover,
            "turnover_share_lt_threshold": turnover_share_lt_threshold,
            "flag_gender_homogeneous": flag_gender_homogeneous,
            "flag_gender_diff_from_applicant": flag_gender_diff_from_applicant,
            "gender_group": gender_group,
            "flag_nationality_homogeneous": flag_nationality_homogeneous,
            "flag_nationality_diff_from_applicant": flag_nationality_diff_from_applicant,
            "nationality_group": nationality_group,
            "flag_occupation_homogeneous": flag_occupation_homogeneous,
            "flag_occupation_diff_from_applicant": flag_occupation_diff_from_applicant,
            "occupation_group": occupation_group,
            "shared_agreements_text": shared_agreements_text,
        })

    if not rows:
        return pd.DataFrame(
            columns=[
                "vacant_unit",
                "apartment",
                "flag_age_gap",
                "nearest_age_gap_years",
                "nearest_age_gap_direction",
                "flag_high_turnover",
                "turnover_share_lt_threshold",
                "flag_gender_homogeneous",
                "flag_gender_diff_from_applicant",
                "gender_group",
                "flag_nationality_homogeneous",
                "flag_nationality_diff_from_applicant",
                "nationality_group",
                "flag_occupation_homogeneous",
                "flag_occupation_diff_from_applicant",
                "occupation_group",
                "shared_agreements_text",
            ]
        )

    return pd.DataFrame(rows)


def build_flag_notes(df_in: pd.DataFrame) -> pd.DataFrame:
    out = df_in.copy()

    def row_notes(row):
        notes = []

        if row.get("flag_gender_homogeneous", False):
            grp = row.get("gender_group")
            if grp:
                notes.append(f"Gender homogeneous ({grp})")
            else:
                notes.append("Gender homogeneous")

        if row.get("flag_age_gap", False):
            gap = row.get("nearest_age_gap_years")
            direction = row.get("nearest_age_gap_direction")
            if pd.notna(gap) and direction:
                notes.append(f"Nearest age neighbour {gap:.0f}y {direction}")
            else:
                notes.append("No resident within 5 years")

        if row.get("flag_nationality_diff_from_applicant", False):
            notes.append("Nationality homogeneous and differs from applicant")
        elif row.get("flag_nationality_homogeneous", False):
            notes.append("Nationality homogeneous")

        if row.get("flag_occupation_homogeneous", False):
            grp = row.get("occupation_group")
            if grp:
                notes.append(f"Occupation homogeneous ({grp})")
            else:
                notes.append("Occupation homogeneous")

        if row.get("flag_high_turnover", False):
            share = row.get("turnover_share_lt_threshold")
            if pd.notna(share):
                notes.append(f"High turnover ({share:.0%} <40d)")
            else:
                notes.append("High turnover")

        return " | ".join(notes)

    out["notes"] = out.apply(row_notes, axis=1)
    return out


def attach_context_flags(
    base_df: pd.DataFrame,
    flags_df: pd.DataFrame,
) -> pd.DataFrame:
    merge_cols = [
        "vacant_unit",
        "apartment",
        "flag_age_gap",
        "nearest_age_gap_years",
        "nearest_age_gap_direction",
        "flag_high_turnover",
        "turnover_share_lt_threshold",
        "flag_gender_homogeneous",
        "flag_gender_diff_from_applicant",
        "gender_group",
        "flag_nationality_homogeneous",
        "flag_nationality_diff_from_applicant",
        "nationality_group",
        "flag_occupation_homogeneous",
        "flag_occupation_diff_from_applicant",
        "occupation_group",
        "shared_agreements_text",
        "notes",
    ]

    available_merge_cols = [c for c in merge_cols if c in flags_df.columns]

    out = base_df.merge(
        flags_df[available_merge_cols],
        on=["vacant_unit", "apartment"],
        how="left",
    )

    for col in CONTEXT_FLAG_COLS:
        if col in out.columns:
            out[col] = out[col].fillna(False)

    for col in CONTEXT_GROUP_COLS:
        if col in out.columns:
            out[col] = out[col].fillna("")

    if "nearest_age_gap_direction" in out.columns:
        out["nearest_age_gap_direction"] = out["nearest_age_gap_direction"].fillna("")

    if "notes" in out.columns:
        out["notes"] = out["notes"].fillna("")

    if "shared_agreements_text" in out.columns:
        out["shared_agreements_text"] = out["shared_agreements_text"].fillna("")

    return out


# ======================================
# Recommendation pipeline
# ======================================
def run_recommender(
    df_in: pd.DataFrame,
    applicant_unit: str,
    top_n: int,
    min_pair_threshold: float,
    exclude_flags: list[str],
) -> tuple[pd.DataFrame, dict]:
    personality_matrices = build_personality_matrices_cached(df_in)
    C_lifestyle = build_lifestyle_matrix_cached(df_in)
    vacant_units_df = build_vacant_units(df_in)

    applicant_row = df_in.loc[df_in["unit"] == applicant_unit].iloc[0]

    C_personality, selected_profile = get_applicant_personality_matrix(
        applicant_row=applicant_row,
        personality_matrices=personality_matrices,
        priority_col=DISPLAY_PRIORITY_COL,
    )

    importance_min = float(df_in[DISPLAY_IMPORTANCE_COL].min())
    importance_max = float(df_in[DISPLAY_IMPORTANCE_COL].max())
    layer_weights = get_layer_weights(
        importance_value=applicant_row[DISPLAY_IMPORTANCE_COL],
        observed_min=importance_min,
        observed_max=importance_max,
    )

    C_final = build_final_pairwise_matrix(
        C_personality=C_personality,
        C_lifestyle=C_lifestyle,
        personality_weight=layer_weights["personality_weight"],
        lifestyle_weight=layer_weights["lifestyle_weight"],
    )

    structural_scores_df = applicant_vacancy_structural_scores(
        applicant_unit=applicant_unit,
        vacancy_df=vacant_units_df,
        tenant_df=df_in,
        C_final=C_final,
    )
    recs_df = add_structural_score(structural_scores_df)

    flags_df = applicant_vacancy_context_flags(
        applicant_unit=applicant_unit,
        vacancy_df=vacant_units_df,
        tenant_df=df_in,
    )
    flags_df = build_flag_notes(flags_df)

    recs_df = attach_context_flags(recs_df, flags_df)

    if min_pair_threshold > 0:
        recs_df = recs_df.loc[recs_df["min_pair"] >= min_pair_threshold].copy()

    for label in exclude_flags:
        col = FLAG_FILTER_MAP[label]
        recs_df = recs_df.loc[~recs_df[col]].copy()

    recs_df = recs_df.sort_values(
        by=["struct_score", "fairness", "harmony"],
        ascending=False,
    ).reset_index(drop=True)

    if top_n > 0:
        recs_df = recs_df.head(top_n).copy()

    meta = {
        "selected_profile": selected_profile,
        "personality_weight": layer_weights["personality_weight"],
        "lifestyle_weight": layer_weights["lifestyle_weight"],
        "n_vacancies": len(vacant_units_df),
        "n_results": len(recs_df),
    }

    return recs_df, meta


# ======================================
# Display helpers
# ======================================
def clean_text(value, default: str = "Not specified") -> str:
    if pd.isna(value):
        return default
    text = str(value).strip()
    if not text or text.lower() in {"nan", "none"}:
        return default
    text = text.replace("_", " ")
    return text[0].upper() + text[1:]


def clean_lower_text(value, default: str = "not specified") -> str:
    text = clean_text(value, default=default)
    return text.lower() if text != "Not specified" else default


def clean_int(value, default: str = "Not specified") -> str:
    if pd.isna(value):
        return default
    try:
        return str(int(float(value)))
    except (ValueError, TypeError):
        return default


def score_to_100(value: float) -> int:
    if pd.isna(value):
        return 0
    return int(round(float(value) * 100))


def match_quality_label(score_100: int) -> str:
    if score_100 >= 85:
        return "Excellent fit"
    if score_100 >= 75:
        return "Strong fit"
    if score_100 >= 65:
        return "Moderate fit"
    return "Mixed fit"


def build_profile_alias_map(df_in: pd.DataFrame) -> dict[str, dict[str, str]]:
    alias_map: dict[str, dict[str, str]] = {}
    units = sorted(df_in["unit"].astype(str).unique().tolist())

    for idx, unit in enumerate(units):
        base_name = DEMO_NAMES[idx % len(DEMO_NAMES)]
        repeat_idx = idx // len(DEMO_NAMES)
        demo_name = base_name if repeat_idx == 0 else f"{base_name} {repeat_idx + 1}"

        alias_map[unit] = {
            "name": demo_name,
            "label": demo_name,
        }

    return alias_map


def build_considerations(row: pd.Series) -> list[str]:
    items = []

    if row.get("flag_age_gap", False):
        gap = row.get("nearest_age_gap_years")
        direction = row.get("nearest_age_gap_direction")
        if pd.notna(gap) and direction:
            items.append(f"Closest resident is about {int(round(gap))} years {direction}.")
        else:
            items.append("No current resident is within 5 years of your age.")

    if row.get("flag_high_turnover", False):
        items.append("At least half of the current flat has fewer than 40 days remaining.")

    if row.get("flag_gender_diff_from_applicant", False):
        items.append("All current residents share the same gender and it differs from yours.")

    if row.get("flag_nationality_diff_from_applicant", False):
        items.append("All current residents share one nationality and it differs from yours.")
    elif row.get("flag_nationality_homogeneous", False):
        items.append("All current residents share one nationality.")

    if row.get("flag_occupation_diff_from_applicant", False):
        items.append("All current residents share the same occupation and it differs from yours.")

    return items


def apartment_title(row: pd.Series) -> str:
    room_no = extract_unit_number(row.get("vacant_unit"))
    apartment = row.get("apartment", "Unknown")
    if room_no is None:
        return f"Apartment {apartment}"
    return f"Apartment {apartment} · Room {room_no}"


def build_shared_agreements_list(row: pd.Series) -> list[str]:
    text = row.get("shared_agreements_text", "")
    if pd.isna(text):
        return []
    return [item.strip() for item in str(text).split(" | ") if item.strip()]


def build_shared_agreements_text(row: pd.Series) -> str:
    return " | ".join(build_shared_agreements_list(row))



def build_considerations_text(row: pd.Series) -> str:
    considerations = build_considerations(row)
    return " | ".join(considerations)


def get_card_tone_class(rank: int) -> str:
    if rank == 1:
        return "rec-rank-1"
    if rank == 2:
        return "rec-rank-2"
    if rank == 3:
        return "rec-rank-3"
    return "rec-rank-default"


def build_person_icon_html(occupied: bool) -> str:
    icon_class = "occupied-icon" if occupied else "free-icon"
    return (
        f'<span class="person-icon {icon_class}">'
        '<svg viewBox="0 0 14 18" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">'
        '<circle cx="7" cy="3" r="2.5"></circle>'
        '<rect x="5.4" y="6" width="3.2" height="6.1" rx="1.4"></rect>'
        '<rect x="2.6" y="7" width="2" height="5.2" rx="0.95"></rect>'
        '<rect x="9.4" y="7" width="2" height="5.2" rx="0.95"></rect>'
        '<rect x="4.5" y="11.3" width="2.1" height="6.1" rx="0.95"></rect>'
        '<rect x="7.4" y="11.3" width="2.1" height="6.1" rx="0.95"></rect>'
        '</svg>'
        '</span>'
    )


def build_occupancy_html(row: pd.Series) -> str:
    apartment_size = row.get("apartmentsize", np.nan)
    n_residents = row.get("n_residents", np.nan)

    if pd.isna(apartment_size) or pd.isna(n_residents):
        return ""

    total_slots = max(int(round(float(apartment_size))), 0)
    occupied_slots = min(max(int(round(float(n_residents))), 0), total_slots)
    free_slots = max(total_slots - occupied_slots, 0)

    icons = "".join(build_person_icon_html(True) for _ in range(occupied_slots))
    icons += "".join(build_person_icon_html(False) for _ in range(free_slots))

    room_word = "room" if total_slots == 1 else "rooms"
    label = f"{occupied_slots} of {total_slots} {room_word} currently occupied"

    return (
        '<div class="occupancy-wrap">'
        f'<span class="occupancy-label">{label}</span>'
        f'<span class="occupancy-icons">{icons}</span>'
        '</div>'
    )


def html_list(items: list[str]) -> str:
    if not items:
        return ""
    rows = "".join(f"<li>{escape(str(item))}</li>" for item in items)
    return f'<ul class="rec-list">{rows}</ul>'


def render_recommendation_card(row: pd.Series, rank: int) -> None:
    overall_score = score_to_100(row["struct_score"])
    quality_label = match_quality_label(overall_score)
    considerations = build_considerations(row)
    shared_agreements = build_shared_agreements_list(row)
    card_tone = get_card_tone_class(rank)
    occupancy_html = build_occupancy_html(row)
    shared_html = html_list(shared_agreements)
    considerations_html = html_list(considerations)

    title_html = escape(f"{rank}. {apartment_title(row)}")
    subcopy_html = escape("A suggested shared-living option based on compatibility and apartment context.")

    sections = ""
    if shared_html:
        sections += (
            '<div class="rec-list-block">'
            '<div class="rec-list-title">What you all agree on 100%</div>'
            f'{shared_html}'
            '</div>'
        )

    if considerations_html:
        sections += (
            '<div class="rec-list-block">'
            '<div class="rec-list-title">Things to be aware of</div>'
            f'{considerations_html}'
            '</div>'
        )

    html = (
        f'<div class="rec-card {card_tone}">'
        '<div class="rec-grid">'
        '<div>'
        f'<div class="rec-title">{title_html}</div>'
        f'<div class="rec-subcopy">{subcopy_html}</div>'
        '<div class="rec-meta">'
        f'<a class="apply-link" href="{OPERATOR_URL}" target="_blank">Apply directly</a>'
        f'{occupancy_html}'
        '</div>'
        '</div>'
        '<div>'
        '<div class="rec-score-label">Overall match</div>'
        f'<div class="rec-score-value">{overall_score}/100</div>'
        '</div>'
        '<div>'
        f'<span class="score-pill">{escape(quality_label)}</span>'
        '</div>'
        '</div>'
        f'{sections}'
        '</div>'
    )
    st.markdown(html, unsafe_allow_html=True)

